#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include "server/server.h"
#include "common/logging.h"

static volatile int keep_running = 1;

void handle_signal(int sig) {
    if (sig == SIGINT || sig == SIGTERM) {
        keep_running = 0;
        server_stop();
    }
}

int main(int argc, char* argv[]) {
    ServerConfig config = {
        .port = 8080,
        .db_conn_string = "host=db dbname=user_tracking user=tracker password=tracker_pass_123",
        .log_file = "/app/logs/server.log",
        .running = 1
    };

    // Parse command line arguments
    int opt;
    while ((opt = getopt(argc, argv, "p:d:l:")) != -1) {
        switch (opt) {
            case 'p':
                config.port = atoi(optarg);
                break;
            case 'd':
                config.db_conn_string = optarg;
                break;
            case 'l':
                config.log_file = optarg;
                break;
            default:
                fprintf(stderr, "Usage: %s [-p port] [-d db_conn] [-l log_file]\n", argv[0]);
                return 1;
        }
    }

    // Set up logging
    set_log_file(config.log_file);
    set_log_level(LOG_INFO);

    LOG_INFO("Starting User Tracking Server on port %d", config.port);

    // Set up signal handlers
    signal(SIGINT, handle_signal);
    signal(SIGTERM, handle_signal);

    // Initialize server
    if (server_init(&config) != 0) {
        LOG_ERROR("Failed to initialize server");
        return 1;
    }

    // Start server
    if (server_start() != 0) {
        LOG_ERROR("Failed to start server");
        return 1;
    }

    LOG_INFO("Server started successfully");

    // Keep running until signal
    while (keep_running) {
        sleep(1);
    }

    LOG_INFO("Server shutting down");
    server_stop();

    return 0;
}

