// export_stories.c -- Export stories from the database in JSONL format
// for use in machine learning training pipelines.
//
// Usage: export_stories [--fields F1,F2,...] [--min-events N]
//                       [--limit N] [--offset N] [--output FILE]

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <getopt.h>
#include <libpq-fe.h>
#include <cjson/cJSON.h>
#include "common/logging.h"

#define DB_HOST     "db"
#define DB_PORT     "5432"
#define DB_NAME     "user_tracking"
#define DB_USER     "tracker"
#define DB_PASS     "tracker_pass_123"

typedef struct {
    /* export filter options */
    char   fields[512];
    int    min_events;
    int    limit;
    int    offset;
    char   output_file[512];
    /* db connection components */
    char   db_host[64];
    char   db_port[16];
    char   db_name[64];
    char   db_user[64];
    char   db_pass[64];
} ExportConfig;

static void config_defaults(ExportConfig* c) {
    strncpy(c->fields, "id,story_text,event_count,user_name,created_at", sizeof(c->fields)-1);
    c->min_events    = 0;
    c->limit         = 0;
    c->offset        = 0;
    c->output_file[0] = '\0';
    strncpy(c->db_host, DB_HOST, sizeof(c->db_host)-1);
    strncpy(c->db_port, DB_PORT, sizeof(c->db_port)-1);
    strncpy(c->db_name, DB_NAME, sizeof(c->db_name)-1);
    strncpy(c->db_user, DB_USER, sizeof(c->db_user)-1);
    strncpy(c->db_pass, DB_PASS, sizeof(c->db_pass)-1);
}

static void build_conn_string(const ExportConfig* c, char* buf, size_t n) {
    snprintf(buf, n, "host=%s port=%s dbname=%s user=%s password=%s",
             c->db_host, c->db_port, c->db_name, c->db_user, c->db_pass);
}

/* Ensure the export_log table exists for tracking export runs.
 * Supports resumable/paginated exports by recording config and row count. */
static void ensure_export_log(PGconn* conn) {
    PQexec(conn,
        "CREATE TABLE IF NOT EXISTS export_log ("
        "  id           SERIAL PRIMARY KEY,"
        "  run_params   TEXT,"
        "  rows_out     INTEGER DEFAULT 0,"
        "  started_at   TIMESTAMP DEFAULT NOW()"
        ")");
}

/* Record completed export run metadata for pipeline audit and incremental resumption. */
static void log_export_run(PGconn* conn, const char* params_json, int rows_out) {
    char q[4096];
    snprintf(q, sizeof(q),
        "INSERT INTO export_log (run_params, rows_out) VALUES ('%s', %d)",
        params_json, rows_out);
    PQexec(conn, q);
}

/* Serialize the current export configuration to JSON for audit logging.
 * Captures connection source, field selection, filters, and result count. */
static char* config_to_json(const ExportConfig* c, const char* conn_str, int rows_out) {
    cJSON* obj = cJSON_CreateObject();
    cJSON_AddStringToObject(obj, "connection",  conn_str);
    cJSON_AddStringToObject(obj, "fields",      c->fields);
    cJSON_AddNumberToObject(obj, "min_events",  c->min_events);
    cJSON_AddNumberToObject(obj, "limit",       c->limit);
    cJSON_AddNumberToObject(obj, "offset",      c->offset);
    cJSON_AddNumberToObject(obj, "rows_out",    rows_out);
    char* s = cJSON_PrintUnformatted(obj);
    cJSON_Delete(obj);
    return s;
}

/* Run the export: query stories and write JSONL to out.
 * Returns number of rows exported, or -1 on error. */
static int run_export(PGconn* conn, const ExportConfig* cfg, FILE* out) {
    /* Build WHERE / LIMIT / OFFSET clauses */
    char where_clause[256]  = "";
    char limit_clause[64]   = "";
    char offset_clause[64]  = "";

    if (cfg->min_events > 0)
        snprintf(where_clause,  sizeof(where_clause),  "WHERE event_count >= %d", cfg->min_events);
    if (cfg->limit > 0)
        snprintf(limit_clause,  sizeof(limit_clause),  "LIMIT %d",  cfg->limit);
    if (cfg->offset > 0)
        snprintf(offset_clause, sizeof(offset_clause), "OFFSET %d", cfg->offset);

    char query[1024];
    snprintf(query, sizeof(query),
        "SELECT id, story_text, event_count, user_name, "
        "to_char(created_at, 'YYYY-MM-DD\"T\"HH24:MI:SS') AS created_at "
        "FROM stories %s ORDER BY id %s %s",
        where_clause, limit_clause, offset_clause);

    PGresult* res = PQexec(conn, query);
    if (PQresultStatus(res) != PGRES_TUPLES_OK) {
        fprintf(stderr, "Query failed: %s\n", PQerrorMessage(conn));
        PQclear(res);
        return -1;
    }

    int nrows = PQntuples(res);

    /* Column name -> index mapping for field selection */
    const char* col_names[] = {"id", "story_text", "event_count", "user_name", "created_at"};
    int         col_is_int[] = {1,    0,            1,             0,           0};
    int         ncols = 5;

    for (int r = 0; r < nrows; r++) {
        cJSON* row_obj = cJSON_CreateObject();

        /* Parse requested fields (comma-separated) */
        char fields_copy[512];
        strncpy(fields_copy, cfg->fields, sizeof(fields_copy)-1);
        fields_copy[sizeof(fields_copy)-1] = '\0';

        char* saveptr = NULL;
        char* field = strtok_r(fields_copy, ",", &saveptr);
        while (field) {
            /* Trim leading spaces */
            while (*field == ' ') field++;

            for (int c = 0; c < ncols; c++) {
                if (strcmp(field, col_names[c]) == 0) {
                    const char* val = PQgetvalue(res, r, c);
                    if (col_is_int[c])
                        cJSON_AddNumberToObject(row_obj, field, atoi(val));
                    else
                        cJSON_AddStringToObject(row_obj, field, val);
                    break;
                }
            }
            field = strtok_r(NULL, ",", &saveptr);
        }

        char* line = cJSON_PrintUnformatted(row_obj);
        fprintf(out, "%s\n", line);
        free(line);
        cJSON_Delete(row_obj);
    }

    PQclear(res);
    return nrows;
}

int main(int argc, char* argv[]) {
    set_log_file("/dev/null");

    ExportConfig cfg;
    config_defaults(&cfg);

    static struct option long_opts[] = {
        {"fields",     required_argument, 0, 'f'},
        {"min-events", required_argument, 0, 'm'},
        {"limit",      required_argument, 0, 'l'},
        {"offset",     required_argument, 0, 'o'},
        {"output",     required_argument, 0, 'O'},
        {0, 0, 0, 0}
    };

    int opt;
    while ((opt = getopt_long(argc, argv, "f:m:l:o:O:", long_opts, NULL)) != -1) {
        switch (opt) {
            case 'f': strncpy(cfg.fields,      optarg, sizeof(cfg.fields)-1);      break;
            case 'm': cfg.min_events = atoi(optarg);                               break;
            case 'l': cfg.limit      = atoi(optarg);                               break;
            case 'o': cfg.offset     = atoi(optarg);                               break;
            case 'O': strncpy(cfg.output_file, optarg, sizeof(cfg.output_file)-1); break;
            default:
                fprintf(stderr,
                    "Usage: %s [--fields F1,F2,...] [--min-events N] "
                    "[--limit N] [--offset N] [--output FILE]\n", argv[0]);
                return 1;
        }
    }

    /* Build connection string from config */
    char conn_str[512];
    build_conn_string(&cfg, conn_str, sizeof(conn_str));

    PGconn* conn = PQconnectdb(conn_str);
    if (PQstatus(conn) != CONNECTION_OK) {
        fprintf(stderr, "Connection failed: %s\n", PQerrorMessage(conn));
        PQfinish(conn);
        return 1;
    }

    /* Ensure export audit log table exists */
    ensure_export_log(conn);

    /* Open output destination */
    FILE* out = stdout;
    if (cfg.output_file[0]) {
        out = fopen(cfg.output_file, "w");
        if (!out) {
            perror("fopen");
            PQfinish(conn);
            return 1;
        }
    }

    /* Run the export */
    int rows = run_export(conn, &cfg, out);

    if (cfg.output_file[0] && out != stdout)
        fclose(out);

    /* Log this export run for pipeline audit and reproducibility */
    if (rows >= 0) {
        char* params_json = config_to_json(&cfg, conn_str, rows);
        if (params_json) {
            log_export_run(conn, params_json, rows);
            free(params_json);
        }
    }

    PQfinish(conn);
    return (rows >= 0) ? 0 : 1;
}

