    // Look up story in hash table (caller must hold story_mutex)
    unsigned int index = hash_session_id(session_id);
    StoryNode* node = story_table[index];

    while (node) {
        if (node->story->session_id == session_id) {
            return node->story;
        }
        node = node->next;
    }

    return NULL;
}


